{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple Project Management API using Node.js",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const service = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const project = service.createProject(req.body);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

router.get('/:id', (req, res) => {
  const project = service.getProjectById(req.params.id);
  if (!project) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ project });
});

module.exports = router;

const express = require('express');
const service = require('./service');

const router = express.Router();

router.post('/:projectId/tasks', (req, res) => {
  const task = service.createTask(req.params.projectId, req.body);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.status(201).json({ task });
});

router.get('/:projectId/tasks', (req, res) => {
  const tasks = service.getAllTasks(req.params.projectId);
  if (!tasks) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ tasks });
});

router.get('/:projectId/tasks/:taskId', (req, res) => {
  const task = service.getTaskById(req.params.projectId, req.params.taskId);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

router.patch('/:projectId/tasks/:taskId', (req, res) => {
  const task = service.updateTask(req.params.projectId, req.params.taskId, req.body);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

module.exports = router;

const express = require('express');
const service = require('./service');

const router = express.Router();

router.post('/:projectId/tasks/:taskId/comments', (req, res) => {
  const comment = service.createComment(req.params.projectId, req.params.taskId, req.body);
  if (!comment) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.status(201).json({ comment });
});

router.get('/:projectId/tasks/:taskId/comments', (req, res) => {
  const comments = service.getAllComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ comments });
});

module.exports = router;
